"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  CUSTOMERS,
  VERDICT_LABEL,
  VERDICT_COLOR,
  TAG_LABEL,
  TRIAGE_BANDS,
  bandForCustomer,
  healthBand,
  customersAllMetrics,
  customersAllAI,
  type CustomerRow,
  type CustomerVerdict,
} from "@/features/customers/api/customers-all-data";
import "./all.css";

const PERIOD_LABELS = ["MTD", "Last month", "Last 90 days", "Last 12 months"];

type SortKey = "name" | "ltv" | "orders" | "margin" | "health" | null;
type SegFilter = "all" | "vip" | "repeat" | "atrisk" | "new" | "release";
type HealthFilter = "all" | "healthy" | "watch" | "atrisk";
type ChannelFilter = "all" | "Organic" | "Paid Google" | "Paid Meta" | "Direct" | "Email" | "Social";

const SEG_FILTERS: Array<{ id: SegFilter; label: string }> = [
  { id: "all", label: "All" },
  { id: "vip", label: "VIP" },
  { id: "repeat", label: "Repeat" },
  { id: "atrisk", label: "At risk" },
  { id: "new", label: "New" },
  { id: "release", label: "Drains" },
];

export default function AllCustomersPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const [seg, setSeg] = useState<SegFilter>("all");
  const [hFilter, setHFilter] = useState<HealthFilter>("all");
  const [chan, setChan] = useState<ChannelFilter>("all");
  const [query, setQuery] = useState("");
  const [sortKey, setSortKey] = useState<SortKey>(null);
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const { openBridge } = useBridge();

  const rows = useMemo(() => {
    let list = CUSTOMERS.filter((c) => {
      if (seg === "vip" && !c.tags.includes("vip")) return false;
      if (seg === "repeat" && (!c.tags.includes("repeat") || c.tags.includes("vip"))) return false;
      if (seg === "atrisk" && !(c.tags.includes("atrisk") || c.tags.includes("cold"))) return false;
      if (seg === "new" && !c.tags.includes("new")) return false;
      if (seg === "release" && !c.tags.includes("discount")) return false;
      if (hFilter !== "all" && healthBand(c.health) !== hFilter) return false;
      if (chan !== "all" && c.channel !== chan) return false;
      if (query) {
        const q = query.toLowerCase();
        if (!c.name.toLowerCase().includes(q) && !c.email.toLowerCase().includes(q)) return false;
      }
      return true;
    });
    if (sortKey) {
      const dir = sortDir;
      list = [...list].sort((a, b) => {
        if (sortKey === "name") return dir * a.name.localeCompare(b.name);
        return dir * ((a[sortKey] as number) - (b[sortKey] as number));
      });
    }
    return list;
  }, [seg, hFilter, chan, query, sortKey, sortDir]);

  const onSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "name" ? 1 : -1);
    }
  };
  const th = (k: SortKey, label: string, num = false, ctr = false) => (
    <span
      className={`th${num ? " num" : ""}${ctr ? " ctr" : ""}${sortKey === k ? " active" : ""}`}
      onClick={() => onSort(k)}
    >
      {label}
      {sortKey === k && <span className="ar">{sortDir < 0 ? "↓" : "↑"}</span>}
    </span>
  );

  /** Group rows into the triage bands. */
  const grouped = useMemo(() => {
    const buckets: Record<string, CustomerRow[]> = { attention: [], vip: [], other: [] };
    rows.forEach((c) => {
      // Skip sorting/banding when an explicit sort is active — render as flat list
      if (sortKey) buckets.other.push(c);
      else buckets[bandForCustomer(c)].push(c);
    });
    return buckets;
  }, [rows, sortKey]);

  return (
    <div className="customers-all-page">
      <DeptHeader
        dept="customers"
        title="All Customers"
        meta={
          <>
            <span className="live">Live</span> · WooCommerce · 2,140 customers · synced 2 min ago
          </>
        }
        actions={
          <>
            <button className="btn-util">Export CSV</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("customers")}
            >
              Launch campaign → Bridge
            </button>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Total customers</div>
          <div className="metric-v">{customersAllMetrics.total}</div>
          <div className="metric-s up">{customersAllMetrics.totalSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Repeat rate</div>
          <div className="metric-v green">{customersAllMetrics.repeatRate}</div>
          <div className="metric-s up">{customersAllMetrics.repeatRateSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Average LTV</div>
          <div className="metric-v">{customersAllMetrics.avgLtv}</div>
          <div className="metric-s">{customersAllMetrics.avgLtvSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Needs attention</div>
          <div className="metric-v red">{customersAllMetrics.attention}</div>
          <div className="metric-s down">{customersAllMetrics.attentionSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">VIP customers</div>
          <div className="metric-v vip">{customersAllMetrics.vip}</div>
          <div className="metric-s">{customersAllMetrics.vipSub}</div>
        </div>
      </div>

      <AIStrip label={customersAllAI.label} meta={customersAllAI.meta} cards={customersAllAI.cards} />

      {/* Tools row */}
      <div className="tools-row">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="11" cy="11" r="7" />
            <path d="M21 21l-4.3-4.3" />
          </svg>
          <input
            type="text"
            placeholder="Search by name or email…"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
        </div>
        <div className="rows-ctl">
          <span className="rows-count">{rows.length} of {CUSTOMERS.length}</span>
        </div>
      </div>

      {/* Filter row */}
      <div className="filter-row">
        <div className="filters">
          {SEG_FILTERS.map((f) => (
            <button
              key={f.id}
              className={`fchip${seg === f.id ? " active" : ""}`}
              type="button"
              onClick={() => setSeg(f.id)}
            >
              {f.label}
            </button>
          ))}
        </div>
        <div className="fselect-wrap">
          <select
            className="fselect"
            value={hFilter}
            onChange={(e) => setHFilter(e.target.value as HealthFilter)}
            aria-label="Filter by health"
          >
            <option value="all">All health</option>
            <option value="healthy">Healthy</option>
            <option value="watch">Watch</option>
            <option value="atrisk">At risk</option>
          </select>
          <select
            className="fselect"
            value={chan}
            onChange={(e) => setChan(e.target.value as ChannelFilter)}
            aria-label="Filter by channel"
          >
            <option value="all">All channels</option>
            <option value="Organic">Organic</option>
            <option value="Paid Google">Paid Google</option>
            <option value="Paid Meta">Paid Meta</option>
            <option value="Direct">Direct</option>
            <option value="Email">Email</option>
            <option value="Social">Social</option>
          </select>
        </div>
      </div>

      {/* Ledger */}
      <div className="ledger">
        <div className="ldg-head">
          {th("name", "Customer")}
          <span className="th">Location</span>
          {th("ltv", "Lifetime value", true)}
          {th("orders", "Orders", true)}
          <span className="th num">Last order</span>
          {th("margin", "Margin", true)}
          {th("health", "Health", false, true)}
          <span className="th num">Verdict</span>
        </div>

        {sortKey ? (
          // Sorted: flat list, no bands
          grouped.other.map((c) => <CustRow key={c.id} c={c} />)
        ) : (
          // Triaged: bands
          <>
            {TRIAGE_BANDS.map((b) => {
              const list = grouped[b.id] ?? [];
              if (list.length === 0) return null;
              return (
                <div key={b.id}>
                  <div
                    className="ldg-band"
                    style={{
                      ["--band-c" as string]: b.color,
                      ["--band-bg" as string]: b.bg,
                    } as React.CSSProperties}
                  >
                    <span className="bl">
                      {b.label}
                      <span className="bcount">{list.length}</span>
                    </span>
                    <span className="br">{b.right}</span>
                  </div>
                  {list.map((c) => <CustRow key={c.id} c={c} />)}
                </div>
              );
            })}
          </>
        )}

        {rows.length === 0 && (
          <div style={{ padding: "32px 22px", textAlign: "center", color: "var(--ink-3)", fontFamily: "var(--font-mono)", fontSize: 11, letterSpacing: "0.06em", textTransform: "uppercase" }}>
            No customers match these filters
          </div>
        )}

        <div className="foot-note">
          <span className="mk" />
          <p>
            This is the one place a single order appears — inside a person&rsquo;s record, read as <b>behavior</b>, not bookkeeping. The global order list lives in Operations and Finance. Here, every customer is ranked not by what they spent, but by <b>health and margin</b> — so a high-spend, high-return account reads as the liability it is.
          </p>
        </div>
      </div>
    </div>
  );
}

function CustRow({ c }: { c: CustomerRow }) {
  const marginCls = c.margin >= 50 ? "good" : c.margin >= 30 ? "mid" : "low";
  return (
    <div
      className="ldg-row"
      style={{ ["--vstripe" as string]: VERDICT_COLOR[c.verdict] } as React.CSSProperties}
    >
      <div className="ldg-cust">
        <div className="avatar" style={{ ["--av" as string]: c.avatar } as React.CSSProperties}>
          {c.name[0]}
        </div>
        <div style={{ minWidth: 0 }}>
          <div className="ldg-name">{c.name}</div>
          <div className="ldg-email">{c.email}</div>
          <div className="ldg-tags">
            {c.tags.map((t) => (
              <span key={t} className={`tag ${t}`}>
                {TAG_LABEL[t]}
              </span>
            ))}
          </div>
        </div>
      </div>
      <div className="ldg-loc">
        {c.city}
        <span>{c.country}</span>
      </div>
      <div className="ldg-num">${c.ltv.toLocaleString()}</div>
      <div className="ldg-orders">{c.orders}</div>
      <div className="ldg-last">
        <div className="lv">{c.last}</div>
        <div className={`od${c.overdue ? "" : " ok"}`}>{c.overdue ?? "on cycle"}</div>
      </div>
      <div className={`ldg-margin ${marginCls}`}>{c.margin}%</div>
      <div className="ldg-health">
        <HealthDial health={c.health} />
      </div>
      <div className="ldg-verdict">
        <span className={`vpill ${c.verdict}`}>{VERDICT_LABEL[c.verdict as CustomerVerdict]}</span>
      </div>
    </div>
  );
}

function HealthDial({ health }: { health: number }) {
  const r = 16;
  const c = 2 * Math.PI * r;
  const off = c * (1 - health / 100);
  const col =
    health >= 70 ? "var(--d-finance)" : health >= 45 ? "var(--amber)" : "var(--loss)";
  const tick = (val: number) => {
    const a = (val / 100) * 2 * Math.PI - Math.PI / 2;
    const x1 = 21 + 13.5 * Math.cos(a);
    const y1 = 21 + 13.5 * Math.sin(a);
    const x2 = 21 + 18.5 * Math.cos(a);
    const y2 = 21 + 18.5 * Math.sin(a);
    return (
      <line key={val} x1={x1.toFixed(1)} y1={y1.toFixed(1)} x2={x2.toFixed(1)} y2={y2.toFixed(1)} stroke="rgba(0,0,0,0.14)" strokeWidth={1} />
    );
  };
  return (
    <div className="dial">
      <svg width="42" height="42" viewBox="0 0 42 42">
        <g transform="rotate(-90 21 21)">
          <circle cx="21" cy="21" r={r} fill="none" stroke="rgba(0,0,0,0.08)" strokeWidth={3} />
          <circle
            cx="21"
            cy="21"
            r={r}
            fill="none"
            stroke={col}
            strokeWidth={3}
            strokeLinecap="round"
            strokeDasharray={c.toFixed(1)}
            strokeDashoffset={off.toFixed(1)}
          />
        </g>
        {tick(45)}
        {tick(70)}
      </svg>
      <div className="dval">{health}</div>
    </div>
  );
}
