/**
 * Mock data for Customers · All Customers.
 *
 * The page is a triage ledger: each customer ranked by health × margin,
 * with a verdict stripe down the left of the row (Protect / Grow /
 * Recover / Watch / Release). Currency in USD per the canonical rule.
 */

export type CustomerVerdict = "protect" | "grow" | "recover" | "watch" | "release";
export type CustomerTag = "repeat" | "vip" | "atrisk" | "cold" | "highm" | "discount" | "new";
export type Channel = "Organic" | "Paid Google" | "Paid Meta" | "Direct" | "Email" | "Social";
export type HealthBand = "healthy" | "watch" | "atrisk";

export interface CustomerRow {
  id: string;
  name: string;
  email: string;
  city: string;
  country: string;
  channel: Channel;
  tags: CustomerTag[];
  /** Lifetime value in USD. */
  ltv: number;
  orders: number;
  /** Display string e.g. "2mo ago" */
  last: string;
  /** Overdue text or null when on cycle. */
  overdue: string | null;
  /** Margin %, 0-100. */
  margin: number;
  /** Health score 0-100. */
  health: number;
  verdict: CustomerVerdict;
  /** Avatar accent color (matches verdict). */
  avatar: string;
}

