/** Three triage bands the ledger groups rows into. */
export const TRIAGE_BANDS: Array<{
  id: "attention" | "vip" | "other";
  label: string;
  right: string;
  color: string;
  bg: string;
}> = [
  { id: "attention", label: "Needs attention", right: "Verdict · Recover / Protect", color: "var(--amber)", bg: "rgba(184,138,42,0.05)" },
  { id: "vip", label: "VIPs", right: "Verdict · Grow / Protect", color: "#8b6fc7", bg: "rgba(139,111,199,0.05)" },
  { id: "other", label: "All other customers", right: "Verdict · mixed", color: "var(--ink-3)", bg: "rgba(0,0,0,0.02)" },
];

export function bandForCustomer(c: CustomerRow): "attention" | "vip" | "other" {
  if (c.tags.includes("cold") || c.tags.includes("atrisk")) return "attention";
  if (c.tags.includes("vip")) return "vip";
  return "other";
}
